        // (1,	1,	NULL,	NULL,	NULL,	1,	'Offer Letter',	NULL,	NULL,	1,	'<p>Dear <strong> [Employee_Name] </strong>,</p><p><br></p><p>We hope this message finds you well. After careful consideration and thorough discussions, we are pleased to extend an offer for the position of Demo Sales Consultant at <strong> [Company_Name]</strong>. We were impressed by your qualifications, experience, and passion for the Demo industry.</p><p><br></p><p>Please find attached the official offer letter which details the terms and conditions of your employment.</p><p>If you have any questions or require any clarifications, feel free to reach out. We hope to welcome you aboard and are looking forward to working together to achieve our shared vision for a sustainable future.</p><p><br></p><p style=\"text-align: center;\"><strong>[Company_Name]</strong></p><p style=\"text-align: center;\"><strong>[Company_Website] </strong></p><p><br></p>',	'2023-10-27 12:17:47',	'2023-10-27 12:17:47'),
