    /**
     * Seed group_permissions for group_id 1 (admin group)
     * CRITICAL: Super admin needs ALL permissions from ALL roles for full system access
     */
    private function seedGroupPermissionsForAdmin(): void
    {
        // Check if group_id 1 already has sufficient permissions
        $existingCount = DB::table('group_permissions')->where('group_id', 1)->count();
        $totalPermissions = DB::table('permissions')->count();

        if ($existingCount >= $totalPermissions * 0.9) {
            \Log::info("seedGroupPermissionsForAdmin: Group 1 already has {$existingCount} permissions (sufficient), skipping");
            return;
        }

        \Log::info('seedGroupPermissionsForAdmin: Seeding permissions for admin group (group_id 1)');

        // SUPER ADMIN GETS POLICIES FROM ADMINISTRATOR (1) AND STANDARD (2) ROLES ONLY
        // Manager role (3) is not included as it's for position-specific permissions
        $allPolicies = DB::table('group_policies')->whereIn('role_id', [1, 2])->get();

        $inserted = 0;
        foreach ($allPolicies as $policy) {
            // Get all tabs for this policy
            $tabs = DB::table('policies_tabs')->where('policies_id', $policy->id)->get();

            foreach ($tabs as $tab) {
                // Get all permissions for this tab
                $permissions = DB::table('permissions')->where('policies_tabs_id', $tab->id)->get();

                foreach ($permissions as $permission) {
                    // Check if already exists
                    $exists = DB::table('group_permissions')
                        ->where('group_id', 1)
                        ->where('role_id', $policy->role_id)
                        ->where('group_policies_id', $policy->id)
                        ->where('policies_tabs_id', $tab->id)
                        ->where('permissions_id', $permission->id)
                        ->exists();

                    if (!$exists) {
                        DB::table('group_permissions')->insert([
                            'group_id' => 1,
                            'role_id' => $policy->role_id,  // Use the policy's role_id (1, 2, or 3)
                            'group_policies_id' => $policy->id,
                            'policies_tabs_id' => $tab->id,
                            'permissions_id' => $permission->id,
                            'created_at' => now(),
                            'updated_at' => now(),
                        ]);
                        $inserted++;
                    }
                }
            }
        }

        \Log::info("seedGroupPermissionsForAdmin: Inserted {$inserted} permissions for group_id 1");

        $finalCount = DB::table('group_permissions')->where('group_id', 1)->count();
        $coverage = round(($finalCount / $totalPermissions) * 100, 1);
        \Log::info("seedGroupPermissionsForAdmin: Total permissions for group_id 1: {$finalCount} ({$coverage}% coverage)");
    }

    /**
     * Seed profile access permissions for group_id 1 (super admin)
     * CRITICAL: Super admin needs full profile/account access to avoid "Not Permitted" errors
     */
    private function seedProfileAccessForAdmin(): void
    {
        // Check if already configured
        $exists = DB::table('profile_access_permissions')->where('group_id', 1)->exists();

        if ($exists) {
            \Log::info('seedProfileAccessForAdmin: Profile access already configured for group_id 1, skipping');
            return;
        }

        \Log::info('seedProfileAccessForAdmin: Creating profile access permissions for admin group');

        // 1. Profile Access - Super admin can access ALL profiles
        DB::table('profile_access_permissions')->insert([
            'group_id' => 1,
            'role_id' => 1,
            'profile_access_for' => 'all',
            'type' => 'profile_access',
            'created_at' => now(),
            'updated_at' => now(),
        ]);

        // 2. Account Access - Enable all account controls
        DB::table('profile_access_permissions')->insert([
            'group_id' => 1,
            'role_id' => 1,
            'payroll_history' => 1,
            'reset_password' => 1,
            'type' => 'account_access',
            'created_at' => now(),
            'updated_at' => now(),
        ]);

        // 3. Position Access - Leave empty for unrestricted access to all positions
        // No records needed - empty position_access array means "all positions"

        \Log::info('seedProfileAccessForAdmin: Profile access configured successfully');
    }
